import React, { useEffect, useState } from 'react';
import API from '../api/axios';

const STATUS_COLORS = {
  new: '#3b82f6', contacted: '#f59e0b', qualified: '#10b981', closed: '#8b5cf6', lost: '#ef4444'
};

export default function Leads() {
  const [leads, setLeads] = useState([]);
  const [showForm, setShowForm] = useState(false);
  const [form, setForm] = useState({ name:'', phone:'', email:'', source:'website', budget:'', preferences:'' });
  const [filter, setFilter] = useState('all');

  const fetchLeads = () => API.get('/leads').then(r => setLeads(r.data));
  useEffect(() => { fetchLeads(); }, []);

  const handleSubmit = async (e) => {
    e.preventDefault();
    await API.post('/leads', form);
    setShowForm(false);
    setForm({ name:'', phone:'', email:'', source:'website', budget:'', preferences:'' });
    fetchLeads();
  };

  const updateStatus = async (id, status) => {
    const lead = leads.find(l => l.id === id);
    await API.put(`/leads/${id}`, { ...lead, status });
    fetchLeads();
  };

  const deleteLead = async (id) => {
    if (window.confirm('Delete this lead?')) {
      await API.delete(`/leads/${id}`);
      fetchLeads();
    }
  };

  const filtered = filter === 'all' ? leads : leads.filter(l => l.status === filter);

  return (
    <div style={styles.page}>
      <div style={styles.header}>
        <h1 style={styles.title}>📋 Leads</h1>
        <button onClick={() => setShowForm(!showForm)} style={styles.addBtn}>+ Add Lead</button>
      </div>

      {/* Filter tabs */}
      <div style={styles.tabs}>
        {['all','new','contacted','qualified','closed','lost'].map(s => (
          <button key={s} onClick={() => setFilter(s)}
            style={{ ...styles.tab, ...(filter === s ? styles.activeTab : {}) }}>
            {s.charAt(0).toUpperCase() + s.slice(1)}
          </button>
        ))}
      </div>

      {/* Add Lead Form */}
      {showForm && (
        <div style={styles.formBox}>
          <h3 style={{ marginBottom:'16px', color:'#1e293b' }}>New Lead</h3>
          <form onSubmit={handleSubmit} style={styles.formGrid}>
            <input placeholder="Name *" required style={styles.input} value={form.name} onChange={e => setForm({...form, name:e.target.value})} />
            <input placeholder="Phone" style={styles.input} value={form.phone} onChange={e => setForm({...form, phone:e.target.value})} />
            <input placeholder="Email" style={styles.input} value={form.email} onChange={e => setForm({...form, email:e.target.value})} />
            <select style={styles.input} value={form.source} onChange={e => setForm({...form, source:e.target.value})}>
              <option value="website">Website</option>
              <option value="ads">Ads</option>
              <option value="call">Call</option>
              <option value="referral">Referral</option>
            </select>
            <input placeholder="Budget (₹)" type="number" style={styles.input} value={form.budget} onChange={e => setForm({...form, budget:e.target.value})} />
            <input placeholder="Preferences" style={styles.input} value={form.preferences} onChange={e => setForm({...form, preferences:e.target.value})} />
            <div style={{ gridColumn:'1/-1', display:'flex', gap:'10px' }}>
              <button type="submit" style={styles.addBtn}>Save Lead</button>
              <button type="button" onClick={() => setShowForm(false)} style={styles.cancelBtn}>Cancel</button>
            </div>
          </form>
        </div>
      )}

      {/* Leads Table */}
      <div style={styles.tableWrapper}>
        <table style={styles.table}>
          <thead>
            <tr style={styles.thead}>
              <th style={styles.th}>Name</th>
              <th style={styles.th}>Phone</th>
              <th style={styles.th}>Email</th>
              <th style={styles.th}>Source</th>
              <th style={styles.th}>Budget</th>
              <th style={styles.th}>Status</th>
              <th style={styles.th}>Actions</th>
            </tr>
          </thead>
          <tbody>
            {filtered.map(lead => (
              <tr key={lead.id} style={styles.row}>
                <td style={styles.td}><strong>{lead.name}</strong></td>
                <td style={styles.td}>{lead.phone || '—'}</td>
                <td style={styles.td}>{lead.email || '—'}</td>
                <td style={styles.td}>{lead.source}</td>
                <td style={styles.td}>{lead.budget ? `₹${Number(lead.budget).toLocaleString()}` : '—'}</td>
                <td style={styles.td}>
                  <select value={lead.status} onChange={e => updateStatus(lead.id, e.target.value)}
                    style={{ ...styles.badge, background: STATUS_COLORS[lead.status] + '20', color: STATUS_COLORS[lead.status], border:`1px solid ${STATUS_COLORS[lead.status]}` }}>
                    {['new','contacted','qualified','closed','lost'].map(s => <option key={s} value={s}>{s}</option>)}
                  </select>
                </td>
                <td style={styles.td}>
                  <button onClick={() => deleteLead(lead.id)} style={styles.deleteBtn}>🗑️</button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
        {filtered.length === 0 && <div style={styles.empty}>No leads found.</div>}
      </div>
    </div>
  );
}

const styles = {
  page: { padding:'24px' },
  header: { display:'flex', justifyContent:'space-between', alignItems:'center', marginBottom:'20px' },
  title: { fontSize:'22px', fontWeight:'700', color:'#1e293b' },
  addBtn: { padding:'10px 20px', background:'#3b82f6', color:'#fff', border:'none', borderRadius:'8px', cursor:'pointer', fontWeight:'600' },
  cancelBtn: { padding:'10px 20px', background:'#e2e8f0', color:'#475569', border:'none', borderRadius:'8px', cursor:'pointer' },
  tabs: { display:'flex', gap:'8px', marginBottom:'20px', flexWrap:'wrap' },
  tab: { padding:'6px 16px', borderRadius:'20px', border:'1px solid #e2e8f0', background:'#fff', cursor:'pointer', fontSize:'13px', color:'#64748b' },
  activeTab: { background:'#3b82f6', color:'#fff', border:'1px solid #3b82f6' },
  formBox: { background:'#fff', padding:'20px', borderRadius:'10px', marginBottom:'20px', boxShadow:'0 1px 8px rgba(0,0,0,0.08)' },
  formGrid: { display:'grid', gridTemplateColumns:'1fr 1fr', gap:'12px' },
  input: { padding:'10px 12px', border:'1px solid #e2e8f0', borderRadius:'8px', fontSize:'14px', outline:'none' },
  tableWrapper: { background:'#fff', borderRadius:'10px', boxShadow:'0 1px 8px rgba(0,0,0,0.08)', overflow:'hidden' },
  table: { width:'100%', borderCollapse:'collapse' },
  thead: { background:'#f8fafc' },
  th: { padding:'12px 16px', textAlign:'left', fontSize:'13px', fontWeight:'600', color:'#64748b', borderBottom:'1px solid #e2e8f0' },
  row: { borderBottom:'1px solid #f1f5f9' },
  td: { padding:'12px 16px', fontSize:'14px', color:'#374151' },
  badge: { padding:'4px 12px', borderRadius:'20px', fontSize:'12px', fontWeight:'600', cursor:'pointer' },
  deleteBtn: { background:'none', border:'none', cursor:'pointer', fontSize:'16px' },
  empty: { padding:'40px', textAlign:'center', color:'#94a3b8' }
};
